SELECT DISTINCT p.project_id, p.project_name, p.description, p.created_date, p.owner_id, p.status
FROM projects p
JOIN parameter_configs pc ON p.project_id = pc.project_id;

SELECT COUNT(*)
FROM parameter_configs
WHERE workflow_file = '/path/to/workflow/file';

SELECT wp1.parameter_name AS "Parameter", wp2.parameter_name AS "Depends on"
FROM workflow_parameters wp1
LEFT JOIN workflow_parameters wp2 ON wp1.depends_on = wp2.parameter_id;

SELECT wf.file_name, pc.project_name, pc.workflow_file
FROM workflow_files wf
INNER JOIN parameter_configs pc ON wf.file_path = pc.workflow_file;

SELECT project_name 
FROM projects 
WHERE LENGTH(project_name) > 10;

SELECT u.user_name, ph.change_reason
FROM users u
JOIN parameter_history ph ON u.user_id = ph.changed_by
WHERE ph.parameter_id = (
    SELECT parameter_id FROM workflow_parameters WHERE parameter_name = 'role'
);

SELECT AVG(default_value) AS average_default_value 
FROM workflow_parameters 
WHERE param_type = 'numeric';

SELECT 
    (SELECT COUNT(*) FROM users) AS total_users,
    (SELECT COUNT(*) FROM projects) AS total_projects;
